import { ThrottlerModule } from '@nestjs/throttler';

const DEFAULT_TTL = '1m';
const DEFAULT_LIMIT = 100;

/**
 * Per-API rate limit overrides.
 * Key is API name, value is { ttl, limit }.
 */
export const PER_API_LIMITS: Record<string, { ttl: string; limit: number }> = {
  'UserAPI.public': { ttl: '1m', limit: 10 },
  'OrderAPI': { ttl: '1m', limit: 50 },
  'PaymentAPI': { ttl: '1m', limit: 20 },
};

function parseDuration(duration: string): number {
  const match = duration.match(/^(\d+)(ms|s|m|h)$/);
  if (!match) {
    throw new Error(`Invalid duration format: ${duration}`);
  }
  const value = parseInt(match[1], 10);
  const unit = match[2];
  switch (unit) {
    case 'ms': return value;
    case 's': return value * 1000;
    case 'm': return value * 60 * 1000;
    case 'h': return value * 60 * 60 * 1000;
    default: throw new Error(`Unknown duration unit: ${unit}`);
  }
}

/**
 * ThrottlerModule configuration factory.
 * Import this in AppModule:
 *
 * ```typescript
 * @Module({
 *   imports: [getThrottlerModule()],
 * })
 * ```
 */
export function getThrottlerModule() {
  return ThrottlerModule.forRoot([
    {
      ttl: parseDuration(DEFAULT_TTL),
      limit: DEFAULT_LIMIT,
    },
  ]);
}
